import React, { useEffect, useState } from "react";
import Navbar from "../components/Navbar";
import { api } from "../lib/api";
import { useAuth } from "../contexts/AuthContext";
import { toast } from "sonner";
import { Trash2, Plus, X } from "lucide-react";

export default function Dashboard() {
  const { user } = useAuth();
  const [projects, setProjects] = useState([]);
  const [announcements, setAnnouncements] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ title: "", description: "", tags: "", image_url: "", repo_url: "", status: "in_progress" });
  const [busy, setBusy] = useState(false);

  const load = async () => {
    try {
      const [p, a] = await Promise.all([api.get("/projects/mine"), api.get("/announcements")]);
      setProjects(p.data);
      setAnnouncements(a.data);
    } catch (e) {
      toast.error("failed to load");
    }
  };

  useEffect(() => { load(); }, []);

  const submit = async (e) => {
    e.preventDefault();
    setBusy(true);
    try {
      const payload = { ...form, tags: form.tags.split(",").map((t) => t.trim()).filter(Boolean) };
      await api.post("/projects", payload);
      toast.success("project added");
      setShowForm(false);
      setForm({ title: "", description: "", tags: "", image_url: "", repo_url: "", status: "in_progress" });
      load();
    } catch (e) {
      toast.error(e?.response?.data?.detail || "failed to create");
    } finally { setBusy(false); }
  };

  const del = async (id) => {
    if (!confirm("delete this project?")) return;
    try {
      await api.delete(`/projects/${id}`);
      toast.success("deleted");
      load();
    } catch { toast.error("failed"); }
  };

  return (
    <div className="min-h-screen bg-black text-white">
      <Navbar floating={false} />
      <div className="max-w-6xl mx-auto px-6 md:px-10 pt-12 pb-16">
        <div className="flex items-end justify-between mb-10">
          <div>
            <p className="text-white/50 text-sm mb-1">welcome back</p>
            <h1 className="hero-title text-5xl md:text-6xl font-medium" data-testid="dashboard-title">{user?.name || user?.email}</h1>
          </div>
          <button
            onClick={() => setShowForm(true)}
            data-testid="dashboard-new-project-btn"
            className="hidden md:inline-flex items-center gap-2 bg-white text-black rounded-full px-5 py-3 text-sm hover:bg-neutral-200 transition-colors"
          >
            <Plus size={16} /> new project
          </button>
        </div>

        <div className="grid md:grid-cols-3 gap-8">
          <section className="md:col-span-2">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg text-white/80">your projects</h2>
              <button
                onClick={() => setShowForm(true)}
                data-testid="dashboard-new-project-btn-mobile"
                className="md:hidden bg-white text-black rounded-full px-4 py-2 text-xs"
              >+ add</button>
            </div>

            {projects.length === 0 ? (
              <div className="border border-dashed border-white/15 rounded-2xl p-10 text-center text-white/50 text-sm" data-testid="dashboard-empty">
                no projects yet. submit your first one.
              </div>
            ) : (
              <div className="space-y-3" data-testid="dashboard-projects-list">
                {projects.map((p) => (
                  <div key={p.id} className="bg-neutral-900/60 border border-white/10 rounded-2xl p-5 flex items-start gap-4" data-testid={`dashboard-project-${p.id}`}>
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="text-white font-medium">{p.title}</h3>
                        <span className="text-[10px] uppercase tracking-wider text-white/50 bg-white/5 px-2 py-0.5 rounded-full">{p.status.replace("_", " ")}</span>
                      </div>
                      <p className="text-sm text-white/60 line-clamp-2">{p.description}</p>
                      {p.tags?.length > 0 && (
                        <div className="flex gap-1 mt-2 flex-wrap">
                          {p.tags.map((t) => <span key={t} className="text-[11px] text-white/50">#{t}</span>)}
                        </div>
                      )}
                    </div>
                    <button
                      onClick={() => del(p.id)}
                      data-testid={`dashboard-delete-${p.id}`}
                      className="text-white/40 hover:text-red-400 transition-colors p-2"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </section>

          <aside>
            <h2 className="text-lg text-white/80 mb-4">announcements</h2>
            {announcements.length === 0 ? (
              <p className="text-white/40 text-sm">no announcements yet.</p>
            ) : (
              <div className="space-y-3" data-testid="dashboard-announcements">
                {announcements.map((a) => (
                  <div key={a.id} className="bg-neutral-900/60 border border-white/10 rounded-2xl p-4">
                    <div className="text-xs text-white/40 mb-1">{new Date(a.created_at).toLocaleDateString()}</div>
                    <h3 className="text-sm font-medium mb-1">{a.title}</h3>
                    <p className="text-xs text-white/60">{a.body}</p>
                  </div>
                ))}
              </div>
            )}
          </aside>
        </div>
      </div>

      {showForm && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur z-50 flex items-center justify-center p-4" data-testid="project-form-modal">
          <form onSubmit={submit} className="bg-neutral-900 border border-white/10 rounded-3xl p-6 max-w-lg w-full space-y-3">
            <div className="flex items-center justify-between mb-2">
              <h2 className="text-xl font-medium">new project</h2>
              <button type="button" onClick={() => setShowForm(false)} className="text-white/60 hover:text-white"><X size={18} /></button>
            </div>
            <input required value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} placeholder="title" data-testid="form-title" className="w-full bg-black border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-white/30" />
            <textarea required value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} placeholder="description" rows={4} data-testid="form-description" className="w-full bg-black border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-white/30" />
            <input value={form.tags} onChange={(e) => setForm({ ...form, tags: e.target.value })} placeholder="tags (comma-separated)" data-testid="form-tags" className="w-full bg-black border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-white/30" />
            <input value={form.image_url} onChange={(e) => setForm({ ...form, image_url: e.target.value })} placeholder="image url (optional)" data-testid="form-image" className="w-full bg-black border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-white/30" />
            <input value={form.repo_url} onChange={(e) => setForm({ ...form, repo_url: e.target.value })} placeholder="repo url (optional)" data-testid="form-repo" className="w-full bg-black border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-white/30" />
            <select value={form.status} onChange={(e) => setForm({ ...form, status: e.target.value })} data-testid="form-status" className="w-full bg-black border border-white/10 rounded-xl px-4 py-3 text-sm">
              <option value="planned">planned</option>
              <option value="in_progress">in progress</option>
              <option value="completed">completed</option>
            </select>
            <button type="submit" disabled={busy} data-testid="form-submit" className="w-full bg-white text-black rounded-full py-3 text-sm hover:bg-neutral-200 transition-colors disabled:opacity-50">
              {busy ? "saving..." : "create project"}
            </button>
          </form>
        </div>
      )}
    </div>
  );
}
